#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::CSV;

# Path to the PDF file
my $pdf_file = 'example.pdf';

# Open the PDF file
my $pdf = PDF::API2->open($pdf_file);

# Extract metadata (author and creation date)
my $info = $pdf->info;
my $author = $info->Author;
my $created = $info->CreationDate->format('%Y-%m-%d %T');

print "Author: $author\n";
print "Creation Date: $created\n";

# Function to extract a table from the PDF
sub extract_table {
    my ($page) = @_;
    my $text = $page->text();
    my @rows = split /\n/, $text;

    my @table;
    for my $row (@rows) {
        my @cells = split /\s{2,}/, $row;
        push @table, \@cells if @cells > 1;
    }

    return \@table;
}

# Loop through each page and extract the table
for my $page_num (1 .. $pdf->pages) {
    my $page = $pdf->page($page_num);
    my $table = extract_table($page);

    print "Table from page $page_num:\n";
    my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });
    foreach my $row (@$table) {
        print $csv->string(@$row), "\n";
    }
}

# Close the PDF file
$pdf->close();
